sys_script_include.script:
var SequenceTest = Class.create();
SequenceTest.prototype = {
    initialize: function() {
    },

    /**
     * Test the complete sequence management scenario
     */
    runTest: function() {
        var tableName = 'x_2025153_windsu_0_git_windsurf';
        var numberField = 'number';

        gs.log('=== Sequence Management Test Started ===');

        // Step 1: Create initial records (1, 2, 3, 4, 5, 6)
        this.createTestRecords(tableName, numberField, 6);

        // Step 2: Create new record (should auto-increment to 7)
        this.createTestRecord(tableName, numberField, 'Test record 7');

        // Step 3: Update record 7 to have number 2
        this.updateRecordNumber(tableName, 7, 2);

        // Step 4: Delete a record and verify sequence adjustment
        this.deleteRecord(tableName, 4);

        gs.log('=== Sequence Management Test Completed ===');
    },

    /**
     * Create multiple test records
     */
    createTestRecords: function(tableName, numberField, count) {
        for (var i = 1; i <= count; i++) {
            var gr = new GlideRecord(tableName);
            gr.initialize();
            gr.setValue('description', 'Test record ' + i);
            gr.setValue(numberField, i);
            gr.insert();
            gs.log('Created record with number: ' + i);
        }
    },

    /**
     * Create a single test record (auto-increment)
     */
    createTestRecord: function(tableName, numberField, description) {
        var gr = new GlideRecord(tableName);
        gr.initialize();
        gr.setValue('description', description);
        // Don't set number - let auto-increment handle it
        gr.insert();
        gs.log('Created record with auto-incremented number: ' + gr.getValue(numberField));
    },

    /**
     * Update a record's number
     */
    updateRecordNumber: function(tableName, oldNumber, newNumber) {
        var gr = new GlideRecord(tableName);
        gr.addQuery(numberField, oldNumber);
        gr.query();

        if (gr.next()) {
            gr.setValue(numberField, newNumber);
            gr.update();
            gs.log('Updated record number from ' + oldNumber + ' to ' + newNumber);
        }
    },

    /**
     * Delete a record by number
     */
    deleteRecord: function(tableName, number) {
        var gr = new GlideRecord(tableName);
        gr.addQuery(numberField, number);
        gr.query();

        if (gr.next()) {
            gr.deleteRecord();
            gs.log('Deleted record with number: ' + number);
        }
    },

    /**
     * Display current sequence
     */
    displaySequence: function(tableName, numberField) {
        var gr = new GlideRecord(tableName);
        gr.orderBy(numberField);
        gr.query();

        gs.log('Current sequence:');
        while (gr.next()) {
            gs.log('Number: ' + gr.getValue(numberField) + ', Description: ' + gr.getValue('description'));
        }
    },

    type: 'SequenceTest'
};
